<?php use App\Helpers\Csrf; use App\Helpers\Sanitizer; use App\Helpers\Url; ?>
<main class="container">
<section class="module-hero"><div><span class="eyebrow">Control de acceso</span><h1>Roles y permisos</h1><p>Define qué puede hacer cada usuario dentro del sistema según su perfil.</p></div><div class="action-row"><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/dashboard')) ?>">Panel</a><a class="btn" href="<?= Sanitizer::html(Url::ruta('/roles/crear')) ?>">Crear rol</a></div></section>
<section class="stats-grid"><article class="stat-card"><strong><?= (int)($estadisticas['total']??0) ?></strong><span>Total</span></article><article class="stat-card"><strong><?= (int)($estadisticas['activos']??0) ?></strong><span>Activos</span></article><article class="stat-card"><strong><?= (int)($estadisticas['inactivos']??0) ?></strong><span>Inactivos</span></article><article class="stat-card"><strong><?= (int)($estadisticas['permisos']??0) ?></strong><span>Permisos</span></article></section>
<section class="card"><form class="filter-form" method="GET"><div class="form-group"><label>Buscar</label><input name="buscar" value="<?= Sanitizer::html($busqueda ?? '') ?>" placeholder="Nombre o descripción"></div><div class="form-group"><label>Estado</label><select name="estado"><option value="">Todos</option><option value="1" <?= ($estado ?? '')==='1'?'selected':'' ?>>Activos</option><option value="0" <?= ($estado ?? '')==='0'?'selected':'' ?>>Inactivos</option></select></div><div class="form-actions compact"><button class="btn">Filtrar</button><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/roles')) ?>">Limpiar</a></div></form></section>
<section class="grid-cards"><?php if(empty($roles)): ?><article class="card empty-state">No se encontraron roles.</article><?php endif; ?><?php foreach($roles as $rol): ?><article class="card module-card"><div class="card-top"><h2><?= Sanitizer::html($rol['nombre']) ?></h2><?= (int)$rol['activo']===1?'<span class="badge badge-success">Activo</span>':'<span class="badge badge-danger">Inactivo</span>' ?></div><p class="muted"><?= Sanitizer::html($rol['descripcion'] ?? '') ?></p><div class="chips"><span class="chip"><?= (int)$rol['total_usuarios'] ?> usuario(s)</span><span class="chip"><?= (int)$rol['total_permisos'] ?> permiso(s)</span></div><p class="muted"><?= Sanitizer::html($rol['permisos_texto'] ?? 'Sin permisos') ?></p><div class="acciones-tabla"><a class="btn btn-mini" href="<?= Sanitizer::html(Url::ruta('/roles/ver/'.$rol['id'])) ?>">Ver</a><a class="btn btn-mini btn-secundario" href="<?= Sanitizer::html(Url::ruta('/roles/editar/'.$rol['id'])) ?>">Editar</a><form method="POST" action="<?= Sanitizer::html(Url::ruta('/roles/estado/'.$rol['id'])) ?>" data-confirm="¿Cambiar estado de este rol?"><?= Csrf::campo() ?><input type="hidden" name="activo" value="<?= (int)$rol['activo']===1?0:1 ?>"><button class="btn btn-mini <?= (int)$rol['activo']===1?'btn-danger':'' ?>" type="submit"><?= (int)$rol['activo']===1?'Desactivar':'Activar' ?></button></form></div></article><?php endforeach; ?></section>
</main>
